import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";
import { filterCoursesByClass } from "../courseReducer";

function Enrollments() {
  // ... (остальной код без изменений до рендеринга теста)

  function startTest(testId) {
    const test = tests.find((t) => t.id === testId);
    if (new Date() > new Date(test.deadline)) {
      toast.error("Дедлайн теста истек!");
      return;
    }

    setTestState((prev) => ({
      ...prev,
      [testId]: { timeLeft: test.duration * 60, answers: [], started: true },
    }));

    const timer = setInterval(() => {
      setTestState((prev) => {
        const newTimeLeft = prev[testId].timeLeft - 1;
        if (newTimeLeft <= 0) {
          clearInterval(timer);
          handleTestSubmit(testId, test.courseId, prev[testId].answers);
          return { ...prev, [testId]: { ...prev[testId], completed: true } };
        }
        return { ...prev, [testId]: { ...prev[testId], timeLeft: newTimeLeft } };
      });
    }, 1000);
  }

  // ... (другие функции без изменений)

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Мои записи</h1>
      {/* ... (остальной код до тестов) */}
      <ul className="list-group">
        {enrollments
          .map((enrollment) => {
            const course = filteredCourses.find(
              (c) => c.id === parseInt(enrollment.courseId)
            );
            return course
              ? {
                  ...enrollment,
                  courseName: course.name,
                  teacherId: course.teacherId,
                  courseDeadline: course.deadline,
                }
              : null;
          })
          .filter((enrollment) => enrollment !== null)
          .map((enrollment) => {
            const test = tests.find((t) => t.courseId === enrollment.courseId);
            const courseGrades = grades.filter(
              (g) => g.courseId === enrollment.courseId
            );
            return (
              <li key={enrollment.id} className="list-group-item">
                {/* ... (другие части без изменений) */}
                {test && !testState[test.id]?.completed && (
                  <div className="mt-3">
                    <h5>
                      Итоговый тест: {test.title} (Дедлайн: {test.deadline})
                    </h5>
                    {new Date() > new Date(test.deadline) ? (
                      <p className="text-danger">Дедлайн теста истек!</p>
                    ) : !testState[test.id]?.started ? (
                      <button
                        onClick={() => startTest(test.id)}
                        className="btn btn-success"
                      >
                        Начать тест
                      </button>
                    ) : (
                      <div>
                        <p>
                          Осталось времени:{" "}
                          {Math.floor(testState[test.id].timeLeft / 60)}:
                          {(testState[test.id].timeLeft % 60)
                            .toString()
                            .padStart(2, "0")}
                        </p>
                        {test.questions.map((q, index) => (
                          <div key={q.id} className="mb-3">
                            <p>{q.text}</p>
                            <div style={{ display: "flex", flexWrap: "wrap" }}>
                              {q.options.map((option, optIndex) => (
                                <div
                                  key={optIndex}
                                  className={`option ${
                                    testState[test.id]?.answers[index] === option
                                      ? "selected"
                                      : ""
                                  }`}
                                  onClick={() => {
                                    const newAnswers = [
                                      ...(testState[test.id]?.answers || []),
                                    ];
                                    newAnswers[index] = option;
                                    setTestState((prev) => ({
                                      ...prev,
                                      [test.id]: {
                                        ...prev[test.id],
                                        answers: newAnswers,
                                      },
                                    }));
                                  }}
                                >
                                  {option}
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                        <button
                          onClick={() =>
                            handleTestSubmit(
                              test.id,
                              test.courseId,
                              testState[test.id].answers
                            )
                          }
                          className="btn btn-primary"
                        >
                          Отправить
                        </button>
                      </div>
                    )}
                  </div>
                )}
                {/* ... (остальной код после теста) */}
              </li>
            );
          })}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleUnenroll}
        message="Вы уверены, что хотите отписаться от этого курса?"
      />
    </div>
  );
}

export default Enrollments;
